import{_ as t,o as a,c as s,ag as r}from"./chunks/framework.DaFyx6Bm.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md","lastUpdated":1783522334000}'),n={name:"getting-started/index.md"};function i(o,e,d,c,p,l){return a(),s("div",null,[...e[0]||(e[0]=[r(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Rapiq (<strong>R</strong>est <strong>Api</strong> <strong>Q</strong>uery) is a TypeScript library family to build an efficient interface between client- and server-side applications. It defines a scheme for the request query — fields, filters, relations, pagination and sort, based on the <a href="https://jsonapi.org/format/" target="_blank" rel="noreferrer">JSON:API</a> specification — but <strong>not</strong> for the response.</p><div class="warning custom-block"><p class="custom-block-title">v2</p><p>These docs cover the upcoming <strong>version 2</strong>, which splits the former single <code>rapiq</code> package into focused <code>@rapiq/*</code> packages. The v1 documentation lives on the <a href="https://github.com/tada5hi/rapiq/tree/v1" target="_blank" rel="noreferrer">v1 branch</a>.</p></div><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>Raw client input is parsed into a typed AST (<code>Query</code>), validated against a <code>Schema</code>, and consumed by backend adapters via the visitor pattern:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client side                          Server side</span></span>
<span class="line"><span>-----------                          -----------</span></span>
<span class="line"><span>Query (AST)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>URLEncoder (@rapiq/codec-url-simple)</span></span>
<span class="line"><span>    │  query string</span></span>
<span class="line"><span>    ▼ ────────────────────────────►  URLDecoder / SimpleParser / ExpressionParser</span></span>
<span class="line"><span>                                          │  validated against Schema + SchemaRegistry</span></span>
<span class="line"><span>                                          ▼</span></span>
<span class="line"><span>                                     Query (AST: Fields, Filters, Pagination, Relations, Sorts)</span></span>
<span class="line"><span>                                          │  accept(visitor)</span></span>
<span class="line"><span>                                          ▼</span></span>
<span class="line"><span>                                     Adapter (@rapiq/sql, @rapiq/typeorm)</span></span>
<span class="line"><span>                                          │</span></span>
<span class="line"><span>                                          ▼</span></span>
<span class="line"><span>                                     SQL fragments / mutated SelectQueryBuilder</span></span></code></pre></div><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>URL key</th><th>Purpose</th></tr></thead><tbody><tr><td><code>fields</code></td><td><code>fields</code></td><td>Return only specific resource fields, or extend the default selection.</td></tr><tr><td><code>filters</code></td><td><code>filter</code></td><td>Filter resources according to specific criteria.</td></tr><tr><td><code>relations</code></td><td><code>include</code></td><td>Include related resources of the primary resource.</td></tr><tr><td><code>pagination</code></td><td><code>page</code></td><td>Limit the number of resources returned from the collection.</td></tr><tr><td><code>sort</code></td><td><code>sort</code></td><td>Sort resources by one or more keys, ascending or descending.</td></tr></tbody></table><h2 id="packages" tabindex="-1">Packages <a class="header-anchor" href="#packages" aria-label="Permalink to &quot;Packages&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Package</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="https://github.com/tada5hi/rapiq/tree/master/packages/core" target="_blank" rel="noreferrer">@rapiq/core</a></td><td>Query AST, visitor interfaces, schema system &amp; registry, parser base classes, errors</td></tr><tr><td><a href="/integrations/simple.html">@rapiq/parser-simple</a></td><td>Parses plain object/array input (URL-query-like &quot;simple&quot; dialect) into a <code>Query</code></td></tr><tr><td><a href="/integrations/expression.html">@rapiq/parser-expression</a></td><td>Parses a function-call expression language (e.g. <code>and(eq(name, &#39;John&#39;), gte(age, &#39;18&#39;))</code>) into a <code>Query</code></td></tr><tr><td><a href="/integrations/url.html">@rapiq/codec-url-simple</a></td><td>URL query-string encoder &amp; decoder for the simple dialect</td></tr><tr><td><a href="/integrations/url.html#expression-dialect">@rapiq/codec-url-expression</a></td><td>URL codec for the expression dialect — a nested filter compound in a single <code>filter=and(...)</code> parameter</td></tr><tr><td><a href="/integrations/url.html#codec-registry">@rapiq/codec-url</a></td><td>Registry dispatching between URL codec dialects via the reserved <code>codec</code> parameter</td></tr><tr><td><a href="/integrations/sql.html">@rapiq/sql</a></td><td>Dialect-agnostic SQL adapter; ships presets for Postgres, MySQL, SQLite, MSSQL &amp; Oracle</td></tr><tr><td><a href="/integrations/typeorm.html">@rapiq/typeorm</a></td><td>Applies a parsed <code>Query</code> to a TypeORM <code>SelectQueryBuilder</code></td></tr></tbody></table><p>Everything composes around the core query AST — install only what each side of your application needs.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/getting-started/installation.html">Installation</a> — add the packages you need.</li><li><a href="/getting-started/quick-start.html">Quick Start</a> — client to database in one walkthrough.</li><li><a href="/guide/">Concepts</a> — the Query AST, schemas and visitors in detail.</li></ul>`,13)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
